      out.write("			    if (!activeTab) {\r\n");
      out.write("			        activeTab = \"attendance\";\r\n");
      out.write("			    }\r\n");
      out.write("			    if (activeTab === \"tasks\") showTasks();\r\n");
      out.write("			    if (activeTab === \"leave\") showLeave();\r\n");
      out.write("			    if (activeTab === \"meetings\") showMeetings();\r\n");
      out.write("			    if (activeTab === \"calendar\") openCalendar();\r\n");
      out.write("			    if (activeTab === \"attendance\") showAttendance();\r\n");
      out.write("			});\r\n");
      out.write("			\r\n");
      out.write("			window.addEventListener(\"beforeunload\", function () {\r\n");
      out.write("			    if (performance.navigation.type === 1) {\r\n");
      out.write("			        sessionStorage.removeItem(\"activeTab\");\r\n");
      out.write("			    }\r\n");
      out.write("			});\r\n");
      out.write("			\r\n");
      out.write("    function hideAllSections() {\r\n");
