      out.write("}\r\n");
      out.write("\r\n");
      out.write("    function showCalendar() {\r\n");
      out.write("        hideAllSections();\r\n");
      out.write("        document.getElementById(\"calendarSection\").style.display = \"block\";\r\n");
      out.write("        document.getElementById(\"calendarFrame\").src = \"calendar.jsp\";\r\n");
      out.write("    }\r\n");
