      out.write("    }\r\n");
      out.write("\r\n");
      out.write("    function showToast(message, type = \"success\") {\r\n");
      out.write("    const toast = document.getElementById(\"toast\");\r\n");
      out.write("    toast.style.display = \"none\";\r\n");
      out.write("    toast.className = \"toast\";\r\n");
      out.write("    toast.offsetHeight;\r\n");
      out.write("    toast.classList.add(type);\r\n");
      out.write("    toast.textContent = message;\r\n");
      out.write("    toast.style.display = \"block\";\r\n");
      out.write("    toast.classList.add(\"show\");\r\n");
      out.write("    setTimeout(() => {\r\n");
      out.write("        toast.classList.remove(\"show\");\r\n");
      out.write("        toast.classList.add(\"hide\");\r\n");
