      out.write("			<!-- ====== BREAK TIME SCRIPT ====== -->\r\n");
      out.write("			<script>\r\n");
      out.write("			let breakStartTime = null;\r\n");
      out.write("			let breakInterval  = null;\r\n");
      out.write("			let totalBreakMs   = 0;\r\n");
      out.write("			let breakEntries   = [];\r\n");
      out.write("\r\n");
      out.write("			function fmtTime(ms) {\r\n");
      out.write("			    const s  = Math.floor(ms / 1000);\r\n");
      out.write("			    const h  = Math.floor(s / 3600);\r\n");
      out.write("			    const m  = Math.floor((s % 3600) / 60);\r\n");
      out.write("			    const sc = s % 60;\r\n");
      out.write("			    return [h, m, sc].map(x => String(x).padStart(2, '0')).join(':');\r\n");
      out.write("			}\r\n");
      out.write("\r\n");
      out.write("			function startBreak() {\r\n");
      out.write("			    if (breakStartTime) return;\r\n");
      out.write("			    breakStartTime = Date.now();\r\n");
      out.write("			    document.getElementById('startBreakBtn').disabled = true;\r\n");
      out.write("			    document.getElementById('endBreakBtn').disabled   = false;\r\n");
      out.write("			    document.getElementById('breakStatusBadge').style.display = 'flex';\r\n");
      out.write("\r\n");
      out.write("			    breakInterval = setInterval(() => {\r\n");
      out.write("			        const elapsed = Date.now() - breakStartTime;\r\n");
      out.write("			        document.getElementById('breakTimer').textContent = fmtTime(elapsed);\r\n");
      out.write("			    }, 1000);\r\n");
      out.write("			}\r\n");
      out.write("\r\n");
      out.write("			function endBreak() {\r\n");
      out.write("			    if (!breakStartTime) return;\r\n");
      out.write("			    clearInterval(breakInterval);\r\n");
      out.write("\r\n");
      out.write("			    const dur   = Date.now() - breakStartTime;\r\n");
      out.write("			    totalBreakMs += dur;\r\n");
      out.write("\r\n");
      out.write("			    const start = new Date(breakStartTime);\r\n");
      out.write("			    const end   = new Date();\r\n");
      out.write("			    breakEntries.push({ start, end, dur });\r\n");
      out.write("\r\n");
      out.write("			    renderBreakLog();\r\n");
      out.write("\r\n");
      out.write("			    breakStartTime = null;\r\n");
      out.write("			    document.getElementById('startBreakBtn').disabled = false;\r\n");
      out.write("			    document.getElementById('endBreakBtn').disabled   = true;\r\n");
      out.write("			    document.getElementById('breakStatusBadge').style.display = 'none';\r\n");
      out.write("			    document.getElementById('breakTimer').textContent = '00:00:00';\r\n");
      out.write("			    document.getElementById('totalBreakTime').textContent = fmtTime(totalBreakMs);\r\n");
      out.write("			}\r\n");
      out.write("\r\n");
      out.write("			function renderBreakLog() {\r\n");
      out.write("			    const log = document.getElementById('breakLog');\r\n");
      out.write("			    log.innerHTML = '';\r\n");
      out.write("			    breakEntries.forEach((e, i) => {\r\n");
      out.write("			        const fmt = t => t.toTimeString().substring(0, 8);\r\n");
      out.write("			        const div = document.createElement('div');\r\n");
      out.write("			        div.className = 'break-entry';\r\n");
      out.write("			        div.innerHTML =\r\n");
      out.write("			            '<span class=\"be-label\">Break ' + (i + 1) + ' &nbsp; ' + fmt(e.start) + ' – ' + fmt(e.end) + '</span>' +\r\n");
      out.write("			            '<span class=\"be-dur\">' + fmtTime(e.dur) + '</span>';\r\n");
      out.write("			        log.appendChild(div);\r\n");
      out.write("			    });\r\n");
      out.write("			}\r\n");
      out.write("			</script>\r\n");
      out.write("\r\n");
      out.write("</body>\r\n");
